SELECT AVG(rating) AS average_rating
FROM device_reviews
WHERE device_id = 1;

SELECT rating, review_text, review_date
FROM device_reviews
WHERE device_id = 1 AND rating = 5;

SELECT type_name, type_description
FROM device_types
ORDER BY type_name ASC;

SELECT COUNT(access_id) AS total_accesses
FROM device_access_logs
WHERE user_id = 1;

SELECT rating, review_text
FROM device_reviews
WHERE device_id = 2;

SELECT device_id, AVG(rating) AS average_rating
FROM device_reviews
GROUP BY device_id;
